-- ============================================================================
-- Quiz Seed: Exodus — Part 2 (Chapters 11–20)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══════════════ CHAPTERS 11–15 ═══════════════

-- ═══ Exodus Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 11, 'kids', 1, 'What was the last and worst plague God announced?', 'The firstborn of every Egyptian family and animal would die at midnight', 'A flood', 'An earthquake', 'A fire from heaven', 'a', 'Exodus 11:5 — "And all the firstborn in the land of Egypt shall die, from the firstborn of Pharaoh that sitteth upon his throne, even unto the firstborn of the maidservant."'),
('Exodus', 11, 'kids', 2, 'Would the Israelites be harmed by this plague?', 'No — not even a dog would bark against any Israelite; God put a difference between Egypt and Israel', 'Yes, they would suffer equally', 'Only the old Israelites', 'Only the young Israelites', 'a', 'Exodus 11:7 — "But against any of the children of Israel shall not a dog move his tongue, against man or beast: that ye may know that the LORD doth put a difference between the Egyptians and Israel."'),
('Exodus', 11, 'kids', 3, 'What did God say the Egyptians would give the Israelites?', 'Silver and gold — jewels and precious things', 'Food and water', 'Houses and land', 'Horses and chariots', 'a', 'Exodus 11:2 — "Speak now in the ears of the people, and let every man borrow of his neighbour, and every woman of her neighbour, jewels of silver, and jewels of gold."'),
-- Teens
('Exodus', 11, 'teens', 1, 'How did God say the Egyptians would react to the tenth plague?', 'There would be a great cry throughout Egypt such as there was none like it before, nor shall be like it any more', 'They would celebrate', 'They would ignore it', 'They would blame Moses', 'a', 'Exodus 11:6 — "And there shall be a great cry throughout all the land of Egypt, such as there was none like it, nor shall be like it any more."'),
('Exodus', 11, 'teens', 2, 'What did God say Pharaoh''s servants would do after the tenth plague?', 'They would come to Moses, bow down, and beg the Israelites to leave', 'They would fight Moses', 'They would hide from Moses', 'They would join the Israelites secretly', 'a', 'Exodus 11:8 — "And all these thy servants shall come down unto me, and bow down themselves unto me, saying, Get thee out, and all the people that follow thee: and after that I will go out."'),
('Exodus', 11, 'teens', 3, 'Why did God give the Israelites favour in the sight of the Egyptians?', 'So that the Egyptians would willingly give them silver, gold, and costly items — this was back payment for their years of slave labour', 'So the Egyptians would worship them', 'So they could live in Egypt forever', 'So they could become Egyptian citizens', 'a', 'Exodus 11:3 — "And the LORD gave the people favour in the sight of the Egyptians. Moreover the man Moses was very great in the land of Egypt, in the sight of Pharaoh''s servants, and in the sight of the people."'),
('Exodus', 11, 'teens', 4, 'How did Moses leave Pharaoh after announcing the tenth plague?', 'He went out from Pharaoh in great anger', 'He left calmly and quietly', 'He ran away in fear', 'He stayed to negotiate', 'a', 'Exodus 11:8 — "And he went out from Pharaoh in a great anger."'),
('Exodus', 11, 'teens', 5, 'What had God told Moses about how many plagues it would take?', 'God said Pharaoh would not hearken, so that God''s wonders would be multiplied in Egypt — one more plague and then Pharaoh would drive them out completely', 'One plague would be enough', 'Three plagues maximum', 'Pharaoh would never let them go', 'a', 'Exodus 11:1,9 — "And the LORD said unto Moses, Yet will I bring one plague more upon Pharaoh, and upon Egypt; afterwards he will let you go hence: when he shall let you go, he shall surely thrust you out hence altogether."'),
-- Adults
('Exodus', 11, 'adults', 1, 'How does the tenth plague directly answer Pharaoh''s question "Who is the LORD?"', 'By striking Egypt''s firstborn — from Pharaoh (considered a god) to the lowest servant — God demonstrates His sovereignty over all of Egyptian society, leaving no doubt about who the LORD is', 'It does not answer the question', 'Only the poor are affected', 'Pharaoh''s family is exempt', 'a', 'Exodus 11:5 — The plague spans the entire social hierarchy: "from the firstborn of Pharaoh that sitteth upon his throne, even unto the firstborn of the maidservant that is behind the mill." No class, no person, no god of Egypt is exempt from Yahweh''s judgment.'),
('Exodus', 11, 'adults', 2, 'What is the literary significance of Moses departing "in great anger"?', 'It marks the final break between God''s representative and Pharaoh — after nine plagues and repeated deceptions, righteous anger is the appropriate response to unrepentant evil, mirroring God''s own wrath', 'Moses lost his temper sinfully', 'It was a diplomatic failure', 'Moses was angry at God', 'a', 'Exodus 11:8 — Moses'' anger is not sinful rage but righteous indignation — the fury of a prophet confronting obstinate wickedness. It parallels Jesus'' anger at hardness of heart (Mark 3:5).'),
('Exodus', 11, 'adults', 3, 'How does the "borrowing" (sha''al) of Egyptian wealth fulfil covenant promise?', 'Genesis 15:14 promised Israel would "come out with great substance" — the Hebrew sha''al means "to ask," not "to borrow," so the Egyptians freely gave their wealth, constituting reparations for centuries of forced labour', 'Israel stole from the Egyptians', 'The Egyptians gave nothing', 'It was a temporary loan', 'a', 'Exodus 11:2 — The verb sha''al means "to ask/request." Exodus 12:36 says "the LORD gave the people favour... and they lent unto them." This wealth later furnishes the tabernacle (25:2-7), transforming Egypt''s riches into instruments of worship.'),
('Exodus', 11, 'adults', 4, 'What does "not a dog shall move his tongue against Israel" signify?', 'It indicates total, absolute security — even the most insignificant disturbance (a dog barking) will not touch Israel, demonstrating the completeness of God''s protective discrimination between His people and Egypt', 'Dogs were considered prophetic in Egypt', 'It refers to guard dogs', 'It means dogs will be killed', 'a', 'Exodus 11:7 — "But against any of the children of Israel shall not a dog move his tongue." This vivid image — not even a dog will growl — emphasises the supernatural calm that will prevail over Israel while chaos consumes Egypt.'),
('Exodus', 11, 'adults', 5, 'How does the death of the firstborn serve as measure-for-measure justice?', 'Pharaoh decreed death for Israel''s sons (1:22); now God takes Egypt''s firstborn — the punishment mirrors the crime; additionally, God called Israel "my son, my firstborn" (4:22-23), so Egypt''s firstborn die because Pharaoh refused to release God''s firstborn', 'It was random punishment', 'It was disproportionate', 'It targeted the wrong people', 'a', 'Exodus 4:22-23 + 11:5 — The connection is explicit: "Israel is my son, even my firstborn... if thou refuse to let him go, behold, I will slay thy son, even thy firstborn." The tenth plague is the direct consequence of Pharaoh''s refusal.'),
('Exodus', 11, 'adults', 6, 'Why does the plague strike "from the firstborn of Pharaoh unto the firstborn of the maidservant behind the mill"?', 'It encompasses the entire social spectrum — from throne to mill — demonstrating that Yahweh''s judgment is comprehensive and that complicity in oppression extends to all levels of Egyptian society', 'Only the ruling class deserved judgment', 'The maidservants were innocent', 'It was a random selection', 'a', 'Exodus 11:5 — The phrase "behind the mill" describes the lowest social position — a slave grinding grain. The plague''s universal scope shows that the entire system of oppression is judged, from the king who decreed it to the society that benefited from it.'),
('Exodus', 11, 'adults', 7, 'How does chapter 11 function as the hinge between the plague narrative and the Passover?', 'It serves as both conclusion (the plague announcement) and transition (setting up chapter 12''s Passover instructions) — the announcement of death creates the need for the means of deliverance', 'It is a standalone chapter', 'It repeats earlier material', 'It has no structural function', 'a', 'Chapter 11 announces the sentence (death of firstborn) while chapter 12 provides the remedy (Passover lamb). The literary structure creates tension: judgment is coming, but God provides a way of escape through substitutionary sacrifice.'),
('Exodus', 11, 'adults', 8, 'What Christological foreshadowing is embedded in the tenth plague announcement?', 'The death of the firstborn and the need for a substitute (the Passover lamb) directly foreshadow Christ — God''s own Firstborn (Colossians 1:15) becoming the Lamb of God (John 1:29) whose blood delivers from death', 'There is no connection to Christ', 'Only the blood is symbolic', 'The connection was invented later', 'a', 'The tenth plague establishes the theological framework for the gospel: judgment is universal and deserved, but God provides a substitute whose blood covers those who trust Him. "Christ our passover is sacrificed for us" (1 Corinthians 5:7).');

-- ═══ Exodus Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 12, 'kids', 1, 'What animal did God tell each family to choose for the Passover?', 'A lamb without any spots or blemishes', 'A large cow', 'A white dove', 'A young goat only', 'a', 'Exodus 12:5 — "Your lamb shall be without blemish, a male of the first year: ye shall take it out from the sheep, or from the goats."'),
('Exodus', 12, 'kids', 2, 'What did the Israelites put on their doorframes?', 'The blood of the lamb — on the two side posts and the upper door post', 'Blue paint', 'Olive oil', 'Water from the Nile', 'a', 'Exodus 12:7 — "And they shall take of the blood, and strike it on the two side posts and on the upper door post of the houses, wherein they shall eat it."'),
('Exodus', 12, 'kids', 3, 'What happened at midnight in Egypt?', 'The LORD struck all the firstborn of Egypt — from Pharaoh''s son to the prisoners'' sons and the animals'' firstborn', 'Everyone fell asleep', 'The sun came out', 'The river flooded', 'a', 'Exodus 12:29 — "And it came to pass, that at midnight the LORD smote all the firstborn in the land of Egypt, from the firstborn of Pharaoh that sat on his throne unto the firstborn of the captive that was in the dungeon."'),
-- Teens
('Exodus', 12, 'teens', 1, 'When God saw the blood on the doorposts, what did He do?', 'He passed over that house and the destroyer did not enter — the blood was the sign of protection', 'He knocked on the door', 'He removed the blood', 'He punished that house more', 'a', 'Exodus 12:23 — "For the LORD will pass through to smite the Egyptians; and when he seeth the blood upon the lintel, and on the two side posts, the LORD will pass over the door, and will not suffer the destroyer to come in unto your houses to smite you."'),
('Exodus', 12, 'teens', 2, 'How were the Israelites to eat the Passover meal?', 'With loins girded, shoes on their feet, staff in hand, eating in haste — ready to leave immediately', 'Sitting comfortably at a table', 'Reclining on couches', 'Standing outside their houses', 'a', 'Exodus 12:11 — "And thus shall ye eat it; with your loins girded, your shoes on your feet, and your staff in your hand; and ye shall eat it in haste: it is the LORD''s passover."'),
('Exodus', 12, 'teens', 3, 'Why did the Israelites have to eat unleavened bread?', 'Because they were thrust out of Egypt in such haste that their dough had no time to rise', 'Because they preferred flat bread', 'Because leaven was expensive', 'Because it was healthier', 'a', 'Exodus 12:39 — "And they baked unleavened cakes of the dough which they brought forth out of Egypt, for it was not leavened; because they were thrust out of Egypt, and could not tarry."'),
('Exodus', 12, 'teens', 4, 'How long had the Israelites been in Egypt?', 'Four hundred and thirty years', 'Two hundred years', 'One hundred years', 'Forty years', 'a', 'Exodus 12:40 — "Now the sojourning of the children of Israel, who dwelt in Egypt, was four hundred and thirty years."'),
('Exodus', 12, 'teens', 5, 'Who else left Egypt with the Israelites?', 'A mixed multitude — non-Israelites who joined them, along with flocks, herds, and very much cattle', 'Only the twelve tribes', 'No one else', 'Only the Egyptian priests', 'a', 'Exodus 12:38 — "And a mixed multitude went up also with them; and flocks, and herds, even very much cattle."'),
-- Adults
('Exodus', 12, 'adults', 1, 'How does the Passover lamb typologically point to Christ?', 'The lamb must be without blemish (Christ''s sinlessness), male of the first year (in its prime), its blood applied for protection (Christ''s blood for salvation), no bone broken (John 19:36), and eaten completely — Paul explicitly states "Christ our passover is sacrificed for us" (1 Corinthians 5:7)', 'The parallel is superficial', 'Only the blood connects', 'The connection was not recognised by the apostles', 'a', 'Exodus 12:5-7,46 — The detailed Passover requirements find precise fulfilment in Christ: unblemished (1 Peter 1:19), blood applied (Hebrews 9:22), no bone broken (John 19:36), lamb of God (John 1:29). The typology is comprehensive and intentional.'),
('Exodus', 12, 'adults', 2, 'What is the significance of the blood being placed on the lintel and two doorposts?', 'The blood formed a cross-shaped pattern on the doorframe — blood on top and both sides, with the threshold left uncovered (the blood was not to be trampled); many see this as foreshadowing the cross of Christ', 'The placement was random', 'All four sides were covered', 'Only the top was marked', 'a', 'Exodus 12:7 — Blood on the lintel (top) and two side posts creates a pattern that has been compared to the cross. Hebrews 10:29 warns against those who "trodden under foot the Son of God" — echoing the prohibition against treading on the threshold blood.'),
('Exodus', 12, 'adults', 3, 'What does the command "none of you shall go out at the door of his house until the morning" teach about the nature of salvation?', 'Protection required remaining under the blood — salvation is not merely through initial application but through continued faith and abiding within the covenant; those who left the blood-marked house were unprotected', 'Going outside was merely inconvenient', 'The command was temporary', 'It had no spiritual significance', 'a', 'Exodus 12:22 — "None of you shall go out at the door of his house until the morning." The blood protects only those who remain under it — a principle of abiding in Christ (John 15:4-6) and remaining under the covering of His sacrifice.'),
('Exodus', 12, 'adults', 4, 'Why must the lamb be eaten with bitter herbs and unleavened bread?', 'Bitter herbs (maror) recall the bitterness of slavery; unleavened bread (matzah) represents both the haste of departure and the purity/sincerity of the redeemed life (1 Corinthians 5:8) — the meal combines remembrance of suffering with symbols of new life', 'They were the only available ingredients', 'Bitter herbs aided digestion', 'Unleavened bread was cheaper', 'a', 'Exodus 12:8 — "And they shall eat the flesh in that night, roast with fire, and unleavened bread; and with bitter herbs they shall eat it." Each element carries theological meaning, turning the meal into a multi-sensory teaching tool about redemption.'),
('Exodus', 12, 'adults', 5, 'What does "against all the gods of Egypt I will execute judgment" (12:12) mean?', 'Each plague targeted specific Egyptian deities — the tenth plague, the death of the firstborn, struck at Pharaoh himself (considered the incarnation of Horus) and demonstrated the total defeat of Egypt''s entire religious system', 'It was a general statement with no specifics', 'God only judged Pharaoh', 'The gods were not real so no judgment was needed', 'a', 'Exodus 12:12 — "Against all the gods of Egypt I will execute judgment: I am the LORD." This verse provides the interpretive framework for all ten plagues: they are a systematic theological assault on Egypt''s pantheon, proving each deity impotent before Yahweh.'),
('Exodus', 12, 'adults', 6, 'What is the significance of making Passover "the beginning of months" (12:2)?', 'God recalibrated Israel''s entire calendar around their redemption — the month of liberation (Abib/Nisan) became the first month, making redemption the starting point of time itself, paralleling how the Christian calendar pivots on Christ''s death and resurrection', 'It was an agricultural adjustment', 'It had no symbolic meaning', 'Egypt already used this calendar', 'a', 'Exodus 12:2 — "This month shall be unto you the beginning of months: it shall be the first month of the year to you." God restructures time itself around redemption. Israel''s identity now begins not with creation or patriarchs, but with deliverance — a new beginning.'),
('Exodus', 12, 'adults', 7, 'How does the instruction that "no bone shall be broken" connect to Christ?', 'John 19:36 explicitly cites this as fulfilled when the soldiers did not break Jesus'' legs on the cross — the Passover lamb''s wholeness in death prefigured Christ''s unbroken body, symbolising the completeness and perfection of His sacrifice', 'It was a practical instruction for cooking', 'It applied only to the original Passover', 'John misquotes the text', 'a', 'Exodus 12:46 — "Neither shall ye break a bone thereof." John 19:33,36 — "When they came to Jesus, and saw that he was dead already, they brake not his legs: For these things were done, that the scripture should be fulfilled, A bone of him shall not be broken."'),
('Exodus', 12, 'adults', 8, 'What does the "mixed multitude" who left with Israel suggest about God''s purposes?', 'God''s redemption was not exclusively ethnic — non-Israelites who responded in faith could join the covenant community, foreshadowing the inclusion of Gentiles and the universal scope of salvation', 'They were only servants', 'They caused problems and should not have come', 'They were forced to leave', 'a', 'Exodus 12:38 — "A mixed multitude went up also with them." While this group later caused problems (Numbers 11:4), their inclusion demonstrates that faith, not ethnicity, was the basis for joining God''s people — a principle fully realised in the New Covenant.');

-- ═══ Exodus Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 13, 'kids', 1, 'What did God say the Israelites should do with every firstborn?', 'Set apart (sanctify) every firstborn to God — both of people and animals — because God saved their firstborn in Egypt', 'Sell them for gold', 'Send them to school', 'Give them to Pharaoh', 'a', 'Exodus 13:2 — "Sanctify unto me all the firstborn, whatsoever openeth the womb among the children of Israel, both of man and of beast: it is mine."'),
('Exodus', 13, 'kids', 2, 'What two things did God use to guide the Israelites on their journey?', 'A pillar of cloud by day and a pillar of fire by night', 'A rainbow and thunder', 'A star and a bird', 'A map and a compass', 'a', 'Exodus 13:21 — "And the LORD went before them by day in a pillar of a cloud, to lead them the way; and by night in a pillar of fire, to give them light."'),
('Exodus', 13, 'kids', 3, 'Whose bones did Moses take with them when they left Egypt?', 'Joseph''s bones — because Joseph had made the Israelites promise to carry his bones to the Promised Land', 'Abraham''s bones', 'Jacob''s bones', 'Pharaoh''s bones', 'a', 'Exodus 13:19 — "And Moses took the bones of Joseph with him: for he had straitly sworn the children of Israel, saying, God will surely visit you; and ye shall carry up my bones away hence with you."'),
-- Teens
('Exodus', 13, 'teens', 1, 'Why did God not lead Israel by the shorter road through Philistine territory?', 'Because God said the people might change their minds and return to Egypt if they faced war with the Philistines', 'The road was blocked', 'It was too hot', 'Moses preferred the longer way', 'a', 'Exodus 13:17 — "And it came to pass, when Pharaoh had let the people go, that God led them not through the way of the land of the Philistines, although that was near; for God said, Lest peradventure the people repent when they see war, and they return to Egypt."'),
('Exodus', 13, 'teens', 2, 'What feast did God command Israel to observe forever?', 'The Feast of Unleavened Bread — seven days of eating unleavened bread to remember the exodus', 'The Feast of Harvest', 'The Feast of Tabernacles', 'The Day of Atonement', 'a', 'Exodus 13:6-7 — "Seven days thou shalt eat unleavened bread, and in the seventh day shall be a feast to the LORD. Unleavened bread shall be eaten seven days."'),
('Exodus', 13, 'teens', 3, 'How were parents to explain the firstborn law to their children?', 'Tell them "By strength of hand the LORD brought us out from Egypt, from the house of bondage" — the firstborn belongs to God because He saved Israel''s firstborn', 'They did not need to explain', 'Only priests could explain', 'Children were too young to understand', 'a', 'Exodus 13:14-15 — "And it shall be when thy son asketh thee in time to come, saying, What is this? that thou shalt say unto him, By strength of hand the LORD brought us out from Egypt, from the house of bondage."'),
('Exodus', 13, 'teens', 4, 'What was to be done with the firstborn of a donkey?', 'Redeem it with a lamb, or if not redeemed, break its neck — and all firstborn sons must be redeemed', 'Let it go free', 'Sell it at the market', 'Give it to Pharaoh', 'a', 'Exodus 13:13 — "And every firstling of an ass thou shalt redeem with a lamb; and if thou wilt not redeem it, then thou shalt break his neck: and all the firstborn of man among thy children shalt thou redeem."'),
('Exodus', 13, 'teens', 5, 'Did the pillar of cloud and fire ever leave the Israelites?', 'No — it was always with them, the cloud by day and fire by night, never departing', 'It left them when they sinned', 'It only appeared on special occasions', 'It stayed only for the first week', 'a', 'Exodus 13:22 — "He took not away the pillar of the cloud by day, nor the pillar of fire by night, from before the people."'),
-- Adults
('Exodus', 13, 'adults', 1, 'How does the consecration of the firstborn connect to the Passover and to Christ?', 'Because God spared Israel''s firstborn, every firstborn belongs to Him — this principle of redemption through substitution is fulfilled in Christ, the Firstborn over all creation (Colossians 1:15), who redeems all believers', 'The firstborn law was purely economic', 'It had no connection to Christ', 'It applied only to animals', 'a', 'Exodus 13:2,15 — The firstborn law is rooted in Passover redemption. Christ is both the "firstborn" (prōtotokos) of God (Hebrews 1:6) and the Lamb who redeems — He is simultaneously the firstborn who belongs to God and the sacrifice that redeems all other firstborns.'),
('Exodus', 13, 'adults', 2, 'What is the significance of God leading them "by the way of the wilderness of the Red Sea"?', 'God chose the harder, longer route to protect spiritually immature Israel from premature conflict — divine guidance sometimes takes the longer way because God knows our limitations and timing matters more than speed', 'God made a navigational error', 'The wilderness was easier', 'The Red Sea road was a shortcut', 'a', 'Exodus 13:17-18 — God''s route avoided the Via Maris (Way of the Sea), the main military highway fortified by Egyptian garrisons. God''s guidance prioritises spiritual readiness over geographical efficiency — a principle for all believers.'),
('Exodus', 13, 'adults', 3, 'What is the theology of the pillar of cloud and fire?', 'It represents God''s tangible presence (Shekinah) — guiding (v.21), protecting (14:19-20), and illuminating; the dual form (cloud/fire) shows God provides what is needed for each situation (shade by day, light by night)', 'It was a natural weather phenomenon', 'It was Moses'' invention', 'It appeared only once', 'a', 'Exodus 13:21-22 — The pillar is a theophany — a visible manifestation of God''s presence. Cloud conceals God''s glory while revealing His guidance; fire reveals His presence while providing protection. This continues until the tabernacle is built (40:34-38).'),
('Exodus', 13, 'adults', 4, 'How does Moses'' taking of Joseph''s bones connect the exodus to the patriarchal narrative?', 'It fulfils Joseph''s deathbed request (Genesis 50:25) and demonstrates that the exodus is the continuation of God''s covenant promises to the patriarchs — Israel''s story is one continuous narrative of faithfulness', 'Moses collected the bones by accident', 'Joseph had no bones in Egypt', 'It was an Egyptian custom', 'a', 'Exodus 13:19 — "For he had straitly sworn the children of Israel" (Genesis 50:25). Joseph''s bones serve as a physical testimony of faith — he believed God would fulfil the land promise even though he died in Egypt (Hebrews 11:22).'),
('Exodus', 13, 'adults', 5, 'What educational methodology does God establish in 13:8-10 and 13:14-16?', 'God commands parents to teach children through question-and-answer about the exodus — embedding theology in family life through ritual, narrative, and physical signs (phylacteries/tefillin), making education participatory rather than abstract', 'Education was left to priests only', 'Children were not taught religion', 'Only written texts were used', 'a', 'Exodus 13:8,14 — "Thou shalt shew thy son" and "when thy son asketh thee." God''s pedagogy uses three methods: narrative storytelling (v.8), responsive dialogue (v.14), and physical symbols (v.16 — "a sign upon thine hand, and frontlets between thine eyes").'),
('Exodus', 13, 'adults', 6, 'What does "the LORD went before them" (13:21) teach about divine guidance?', 'God leads from the front, not from behind — He does not merely send His people into unknown territory but personally precedes them, bearing the risk and clearing the way, a model fulfilled in Christ as the Good Shepherd who goes before His sheep (John 10:4)', 'God followed behind them', 'God was absent during travel', 'Moses led independently', 'a', 'Exodus 13:21 — "The LORD went before them." This is personal leadership, not remote direction. The verb halak ("went/walked") indicates God''s active movement with His people — a pattern continued in John 10:4: "He goeth before them, and the sheep follow him."'),
('Exodus', 13, 'adults', 7, 'How does the phrase "God led them not through the way of the land of the Philistines" demonstrate pastoral wisdom?', 'God knew Israel was not yet ready for military conflict — fresh from slavery, they lacked the faith and discipline for war; God''s routing considers the spiritual maturity of His people, not just the fastest path', 'The Philistines were weak', 'The road was closed', 'God wanted Israel to exercise', 'a', 'Exodus 13:17 — The Hebrew phrase "lest the people repent (nacham) when they see war" reveals God''s intimate knowledge of Israel''s psychological state. Divine guidance accounts for what we can bear (cf. 1 Corinthians 10:13).'),
('Exodus', 13, 'adults', 8, 'What is the significance of Israel leaving "harnessed" (chamushim) in 13:18?', 'The Hebrew chamushim can mean "in battle array" or "in orderly ranks" — indicating Israel left Egypt not as a disorganised mob but in military formation, suggesting God''s orderly preparation for the march and future battles', 'They were wearing armour', 'They were carrying weapons from Egypt', 'They were in chains', 'a', 'Exodus 13:18 — "The children of Israel went up harnessed (chamushim) out of the land of Egypt." The term suggests martial organisation — five-abreast formation or armed ranks. God transforms slaves into a nation on the march.');

-- ═══ Exodus Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 14, 'kids', 1, 'What did God do to the Red Sea so the Israelites could cross?', 'He parted the water so they could walk through on dry ground with walls of water on both sides', 'He froze the water', 'He made the water shallow', 'He built a bridge', 'a', 'Exodus 14:21-22 — "And the LORD caused the sea to go back by a strong east wind all that night, and made the sea dry land, and the waters were divided. And the children of Israel went into the midst of the sea upon the dry ground."'),
('Exodus', 14, 'kids', 2, 'What happened to the Egyptian army that chased the Israelites?', 'The water came back and covered all the chariots and soldiers — not one of them survived', 'They turned around and went home', 'They joined the Israelites', 'They swam to safety', 'a', 'Exodus 14:28 — "And the waters returned, and covered the chariots, and the horsemen, and all the host of Pharaoh that came into the sea after them; there remained not so much as one of them."'),
('Exodus', 14, 'kids', 3, 'What did Moses tell the frightened Israelites before the sea parted?', '"Fear ye not, stand still, and see the salvation of the LORD"', '"Run as fast as you can"', '"Build a boat quickly"', '"Fight the Egyptians"', 'a', 'Exodus 14:13 — "And Moses said unto the people, Fear ye not, stand still, and see the salvation of the LORD, which he will shew to you to day."'),
-- Teens
('Exodus', 14, 'teens', 1, 'Why did Pharaoh chase the Israelites after letting them go?', 'He and his servants changed their minds saying "Why have we done this, that we have let Israel go from serving us?" and God hardened his heart', 'Moses invited Pharaoh to follow', 'The Israelites stole Pharaoh''s crown', 'Pharaoh wanted to say goodbye', 'a', 'Exodus 14:5 — "And the heart of Pharaoh and of his servants was turned against the people, and they said, Why have we done this, that we have let Israel go from serving us?"'),
('Exodus', 14, 'teens', 2, 'What did the pillar of cloud do when the Egyptian army was approaching?', 'It moved from in front of Israel to behind them, coming between the two camps — giving darkness to the Egyptians and light to Israel all night', 'It disappeared', 'It moved aside', 'It split in two', 'a', 'Exodus 14:19-20 — "And the angel of God, which went before the camp of Israel, removed and went behind them; and the pillar of the cloud went from before their face, and stood behind them... it was a cloud and darkness to them, but it gave light by night to these."'),
('Exodus', 14, 'teens', 3, 'How did God confuse the Egyptians in the middle of the sea?', 'He took off their chariot wheels so they drove heavily, and the Egyptians said "Let us flee from the face of Israel; for the LORD fighteth for them"', 'He sent a thunderstorm', 'He made them fall asleep', 'He blinded them', 'a', 'Exodus 14:25 — "And took off their chariot wheels, that they drave them heavily: so that the Egyptians said, Let us flee from the face of Israel; for the LORD fighteth for them against the Egyptians."'),
('Exodus', 14, 'teens', 4, 'What were the Israelites'' complaints when they saw the Egyptian army?', '"Were there no graves in Egypt that you brought us to die in the wilderness? It would have been better to serve the Egyptians than to die here"', '"We are ready to fight"', '"Thank you for bringing us here"', '"Let us negotiate with them"', 'a', 'Exodus 14:11-12 — "And they said unto Moses, Because there were no graves in Egypt, hast thou taken us away to die in the wilderness?... For it had been better for us to serve the Egyptians, than that we should die in the wilderness."'),
('Exodus', 14, 'teens', 5, 'What did Israel do after seeing the Egyptians dead on the seashore?', 'They feared the LORD, believed the LORD, and believed in Moses His servant', 'They complained about the food', 'They wanted to go back to Egypt', 'They ignored what happened', 'a', 'Exodus 14:31 — "And Israel saw that great work which the LORD did upon the Egyptians: and the people feared the LORD, and believed the LORD, and his servant Moses."'),
-- Adults
('Exodus', 14, 'adults', 1, 'How does the Red Sea crossing function as both salvation and judgment simultaneously?', 'The same event saves Israel and destroys Egypt — the water that forms walls of protection for God''s people becomes the instrument of death for the oppressors, demonstrating that God''s redemptive acts are simultaneously acts of judgment on evil', 'It was only salvation, not judgment', 'It was only judgment, not salvation', 'Salvation and judgment are unrelated', 'a', 'Exodus 14:21-28 — This dual function — salvation through judgment — is a recurring biblical pattern: the Flood (saving Noah/judging the world), the cross (saving believers/judging sin). The same event reveals both God''s mercy and His justice.'),
('Exodus', 14, 'adults', 2, 'What does "The LORD shall fight for you, and ye shall hold your peace" teach about spiritual warfare?', 'Salvation is ultimately God''s work, not human effort — Israel''s role is to trust and be still while God acts; this principle recurs throughout Scripture: the battle belongs to the Lord (2 Chronicles 20:15)', 'Israel must fight alone', 'Human effort is the primary factor', 'God helps those who help themselves', 'a', 'Exodus 14:14 — "The LORD shall fight for you, and ye shall hold your peace." The Hebrew tacharishun ("be still/silent") commands passivity — a radical statement that salvation is entirely God''s initiative. Cf. Psalm 46:10, Isaiah 30:15.'),
('Exodus', 14, 'adults', 3, 'How does the Red Sea crossing become a baptismal type in the New Testament?', 'Paul explicitly parallels the crossing with baptism (1 Corinthians 10:1-2) — Israel was "baptized unto Moses in the cloud and in the sea"; passing through water symbolises death to the old life (slavery) and resurrection to the new (freedom)', 'Paul makes no such connection', 'Baptism has no Old Testament background', 'The crossing was only physical', 'a', '1 Corinthians 10:1-2 — "Our fathers were under the cloud, and all passed through the sea; And were all baptized unto Moses in the cloud and in the sea." The Red Sea is the paradigmatic OT "baptism" — death to Egypt, resurrection to covenant life.'),
('Exodus', 14, 'adults', 4, 'What does God''s command to "go forward" (14:15) reveal about the relationship between faith and action?', 'After Moses'' faith declaration (v.13-14), God says "speak to the children of Israel, that they go forward" — faith is not passive waiting but active obedience; they must step into the sea before it parts, exercising faith in action', 'God criticised Moses for praying', 'Action replaces faith', 'They should have waited longer', 'a', 'Exodus 14:15 — "Wherefore criest thou unto me? speak unto the children of Israel, that they go forward." There is a time for prayer and a time for action. God commands forward movement — faith acts on God''s word even when the obstacle (the sea) remains.'),
('Exodus', 14, 'adults', 5, 'How does the destruction of Pharaoh''s chariot force connect to the earlier plagues?', 'The chariots represented Egypt''s ultimate military power — their destruction completes the systematic dismantling of Egyptian confidence: religion (plagues), economy (livestock/crops), and now military might; every pillar of Egyptian strength falls before Yahweh', 'Chariots were unimportant', 'The army was small', 'Only some chariots were destroyed', 'a', 'Exodus 14:7,28 — Pharaoh deployed "six hundred chosen chariots, and all the chariots of Egypt" — the full force of the ancient world''s greatest military power. Their total destruction ("there remained not so much as one") demonstrates Yahweh''s absolute supremacy.'),
('Exodus', 14, 'adults', 6, 'What is the significance of "the waters were a wall unto them on their right hand, and on their left"?', 'The wall imagery emphasises the supernatural character of the event — this is not a shallow wadeable crossing but a corridor through deep water, requiring sustained miraculous intervention throughout the passage', 'It was merely ankle-deep water', 'The walls were metaphorical', 'A natural sandbar appeared', 'a', 'Exodus 14:22,29 — "The waters were a wall (chomah) unto them on their right hand, and on their left." The Hebrew chomah means a solid defensive wall — the same word used for city walls. This was not a shallow ford but a supernatural corridor through deep water.'),
('Exodus', 14, 'adults', 7, 'How does the Red Sea event shape Israel''s worship and theology for generations?', 'It becomes the foundational saving act of the Old Testament — referenced in Psalms (66:6, 106:9, 136:13-15), prophets (Isaiah 51:10, 63:11-13), and liturgy; it defines God''s character as the Redeemer who acts in history', 'It was quickly forgotten', 'It was relevant only to that generation', 'Other events were more important', 'a', 'The Red Sea crossing is the Old Testament''s central salvation event, equivalent to the cross for Christians. Over 100 OT references recall it. Psalms celebrate it, prophets invoke it, and Nehemiah 9 makes it central to covenant renewal. It permanently defines who Yahweh is.'),
('Exodus', 14, 'adults', 8, 'What does the phrase "Israel saw the Egyptians dead upon the sea shore" accomplish narratively?', 'It provides visual, undeniable proof that deliverance is complete — the threat is not merely removed but visibly destroyed; Israel needed to see their former masters dead to break the psychological hold of slavery', 'It was incidental detail', 'The Egyptians survived', 'It was a different group of Egyptians', 'a', 'Exodus 14:30 — "And Israel saw the Egyptians dead upon the sea shore." The visual confirmation of death serves a psychological and theological purpose: the power that enslaved them for 430 years is permanently, visibly, undeniably broken.');

-- ═══ Exodus Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 15, 'kids', 1, 'What did Moses and the Israelites do after crossing the Red Sea safely?', 'They sang a song of praise to God — "I will sing unto the LORD, for he hath triumphed gloriously"', 'They went to sleep', 'They built a house', 'They planted a garden', 'a', 'Exodus 15:1 — "Then sang Moses and the children of Israel this song unto the LORD, and spake, saying, I will sing unto the LORD, for he hath triumphed gloriously: the horse and his rider hath he thrown into the sea."'),
('Exodus', 15, 'kids', 2, 'What did Miriam do after the song?', 'She took a tambourine and led all the women in dancing and singing praise to God', 'She cooked dinner', 'She went swimming', 'She took a nap', 'a', 'Exodus 15:20 — "And Miriam the prophetess, the sister of Aaron, took a timbrel in her hand; and all the women went out after her with timbrels and with dances."'),
('Exodus', 15, 'kids', 3, 'What was wrong with the water at Marah?', 'It was too bitter to drink, but God showed Moses a tree to throw in and the water became sweet', 'It was too hot', 'It was frozen', 'There was no water', 'a', 'Exodus 15:23,25 — "And when they came to Marah, they could not drink of the waters of Marah, for they were bitter... and the LORD shewed him a tree, which when he had cast into the waters, the waters were made sweet."'),
-- Teens
('Exodus', 15, 'teens', 1, 'What title does the Song of Moses give God?', '"The LORD is a man of war: the LORD is his name" — celebrating God as a warrior who defeated Egypt', 'The Lord is a builder', 'The Lord is a teacher', 'The Lord is a farmer', 'a', 'Exodus 15:3 — "The LORD is a man of war: the LORD is his name."'),
('Exodus', 15, 'teens', 2, 'What did the song say happened to the Egyptian army in the sea?', '"They sank into the bottom as a stone" and "the depths have covered them" and "thy right hand, O LORD, hath dashed in pieces the enemy"', 'They swam to shore', 'They floated away', 'They were rescued', 'a', 'Exodus 15:5-6 — "The depths have covered them: they sank into the bottom as a stone. Thy right hand, O LORD, is become glorious in power: thy right hand, O LORD, hath dashed in pieces the enemy."'),
('Exodus', 15, 'teens', 3, 'What did Miriam call God in her refrain?', '"Sing ye to the LORD, for he hath triumphed gloriously; the horse and his rider hath he thrown into the sea"', '"God is great and powerful"', '"Praise the Lord of heaven"', '"Blessed be the name of God"', 'a', 'Exodus 15:21 — "And Miriam answered them, Sing ye to the LORD, for he hath triumphed gloriously; the horse and his rider hath he thrown into the sea."'),
('Exodus', 15, 'teens', 4, 'What did the people do just three days after the miraculous Red Sea crossing?', 'They grumbled against Moses because they found no water, then found bitter water at Marah', 'They built a monument', 'They celebrated for seven days', 'They thanked God continuously', 'a', 'Exodus 15:22-24 — "So Moses brought Israel from the Red sea... and they went three days in the wilderness, and found no water. And when they came to Marah, they could not drink... And the people murmured against Moses."'),
('Exodus', 15, 'teens', 5, 'Where did the Israelites camp after Marah and what was special about it?', 'Elim — where there were twelve wells of water and seventy palm trees', 'Jerusalem — a great city', 'Sinai — the mountain of God', 'Bethlehem — a small town', 'a', 'Exodus 15:27 — "And they came to Elim, where were twelve wells of water, and threescore and ten palm trees: and they encamped there by the waters."'),
-- Adults
('Exodus', 15, 'adults', 1, 'What literary genre is the Song of the Sea (15:1-18) and what is its significance?', 'It is a victory hymn (shirah) — considered one of the oldest pieces of Hebrew poetry, likely composed at the time of the event; its archaic Hebrew forms support early dating, and it establishes the pattern for all biblical praise after divine deliverance', 'It is prose narrative', 'It was written centuries later', 'It is a legal document', 'a', 'Exodus 15:1-18 — The Song of the Sea (Shirat Ha-Yam) is one of the oldest texts in the Hebrew Bible. Its archaic language, poetic structure (parallelism, repetition, chiasm), and victory-song genre establish the template for Israel''s worship tradition.'),
('Exodus', 15, 'adults', 2, 'How does the Song of Moses move from past deliverance to future hope?', 'It progresses from the Red Sea victory (vv.1-12) to the effect on surrounding nations (vv.13-16) to God''s ultimate purpose: bringing Israel to His holy dwelling and reigning forever (vv.17-18) — linking exodus to Zion theology', 'It only describes past events', 'It focuses solely on the future', 'It has no structural progression', 'a', 'Exodus 15:13,17-18 — The song''s trajectory: past deliverance (vv.1-12) → nations tremble (vv.14-16) → "Thou shalt bring them in, and plant them in the mountain of thine inheritance" (v.17) → "The LORD shall reign for ever and ever" (v.18). Redemption leads to enthronement.'),
('Exodus', 15, 'adults', 3, 'What is the significance of Miriam being called "the prophetess"?', 'It is the first time a woman is called a prophetess in Scripture — acknowledging her role as a leader in worship and a recipient of divine inspiration alongside Moses and Aaron (cf. Micah 6:4)', 'It was an honorary title with no meaning', 'She was called this by mistake', 'Women could not be prophets', 'a', 'Exodus 15:20 — "Miriam the prophetess." She is the first woman called nevi''ah in the Bible. Micah 6:4 confirms her leadership role: "I sent before thee Moses, Aaron, and Miriam." She functions as a worship leader, musician, and prophet.'),
('Exodus', 15, 'adults', 4, 'What does the Marah incident (15:22-26) reveal about the pattern of faith after deliverance?', 'Just three days after the greatest deliverance in history, Israel grumbles — demonstrating that spiritual highs do not prevent future testing, and that faith must be sustained daily, not based on past experience alone', 'The people had legitimate complaints', 'Three days was too long to travel', 'Moses should have planned better', 'a', 'Exodus 15:22-24 — The juxtaposition of triumphant singing (v.1-21) and bitter complaining (v.24) just three days later is deliberately ironic. The narrative teaches that yesterday''s faith does not automatically carry into today''s trial.'),
('Exodus', 15, 'adults', 5, 'How does God''s healing of the waters at Marah with a tree carry symbolic meaning?', 'The tree (etz) cast into bitter waters to make them sweet is seen as a type of the cross — wood that transforms bitterness into sweetness; God also reveals Himself as "the LORD that healeth thee" (Yahweh Rapha)', 'It was a chemical reaction', 'The tree was magical', 'It had no symbolic meaning', 'a', 'Exodus 15:25-26 — The Hebrew etz can mean tree or wood. The pattern — wood transforming bitter water — has been understood typologically: the cross (wood) transforms the bitterness of sin and death into the sweetness of salvation and life.'),
('Exodus', 15, 'adults', 6, 'What conditional covenant does God establish at Marah?', '"If thou wilt diligently hearken to the voice of the LORD thy God, and wilt do that which is right in his sight... I will put none of these diseases upon thee" — linking obedience to divine healing, anticipating the Sinai covenant', 'There is no covenant at Marah', 'The covenant was unconditional', 'Only sacrifice was required', 'a', 'Exodus 15:26 — This proto-covenant at Marah establishes the obedience-blessing pattern that will be formally codified at Sinai. God reveals Himself as Yahweh Rapha ("the LORD who heals"), making health conditional on covenant faithfulness.'),
('Exodus', 15, 'adults', 7, 'What is the significance of twelve wells and seventy palm trees at Elim?', 'The numbers likely symbolise the twelve tribes of Israel and the seventy elders (cf. Exodus 24:1, Numbers 11:16) — God provides abundantly for His covenant community after the testing at Marah', 'The numbers are coincidental', 'They represent Egyptian deities', 'They have no significance', 'a', 'Exodus 15:27 — Twelve wells for twelve tribes; seventy palms possibly for the seventy elders. After testing (Marah) comes provision (Elim) — a pattern: trial → trust → provision that recurs throughout the wilderness narrative.'),
('Exodus', 15, 'adults', 8, 'How does the phrase "The LORD shall reign for ever and ever" (15:18) shape Israel''s theology of kingship?', 'It declares Yahweh as Israel''s true and eternal King — this theocratic declaration precedes all human kingship in Israel and establishes that any future human king must rule under God''s sovereignty, not in place of it', 'It was a temporary statement', 'It only applied to the wilderness period', 'It referred to Pharaoh', 'a', 'Exodus 15:18 — "The LORD shall reign for ever and ever." This earliest declaration of God''s kingship becomes the foundation for Israel''s political theology. When Israel later demands a human king (1 Samuel 8), God says they have rejected Him as king — directly recalling this confession.');

-- ═══════════════ CHAPTERS 16–20 ═══════════════

-- ═══ Exodus Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 16, 'kids', 1, 'What special food did God send from heaven every morning?', 'Manna — small white flakes that tasted like wafers made with honey', 'Bread and butter', 'Apples', 'Rice', 'a', 'Exodus 16:14-15,31 — "And when the dew that lay was gone up, behold, upon the face of the wilderness there lay a small round thing... And Moses said unto them, This is the bread which the LORD hath given you to eat."'),
('Exodus', 16, 'kids', 2, 'What meat did God send the Israelites in the evening?', 'Quails — birds that covered the camp', 'Fish from the sea', 'Lamb chops', 'Beef', 'a', 'Exodus 16:13 — "And it came to pass, that at even the quails came up, and covered the camp."'),
('Exodus', 16, 'kids', 3, 'What happened when some people tried to keep manna until the next morning?', 'It bred worms and stank — God wanted them to trust Him for fresh manna each day', 'It turned to gold', 'It grew bigger', 'It tasted better', 'a', 'Exodus 16:20 — "Notwithstanding they hearkened not unto Moses; but some of them left of it until the morning, and it bred worms, and stank."'),
-- Teens
('Exodus', 16, 'teens', 1, 'What special rule applied to gathering manna on the sixth day?', 'They were to gather twice as much because no manna would fall on the Sabbath — and the double portion did not spoil overnight', 'They gathered half as much', 'They did not gather at all', 'They gathered three times as much', 'a', 'Exodus 16:22,24,26 — "And it came to pass, that on the sixth day they gathered twice as much bread... he said unto them, To morrow is the rest of the holy sabbath unto the LORD... and it did not stink, neither was there any worm therein."'),
('Exodus', 16, 'teens', 2, 'What did the name "manna" mean?', 'It comes from "What is it?" (man hu) — because the Israelites did not know what it was when they first saw it', 'It means "bread of heaven"', 'It means "God''s gift"', 'It means "morning food"', 'a', 'Exodus 16:15 — "And when the children of Israel saw it, they said one to another, It is manna: for they wist not what it was." The Hebrew man hu literally means "What is it?"'),
('Exodus', 16, 'teens', 3, 'How much manna was each person supposed to gather?', 'An omer per person — and miraculously, those who gathered much had nothing over, and those who gathered little had no lack', 'As much as they could carry', 'Only one handful', 'A full basket', 'a', 'Exodus 16:16,18 — "Gather of it every man according to his eating, an omer for every man... And when they did mete it with an omer, he that gathered much had nothing over, and he that gathered little had no lack."'),
('Exodus', 16, 'teens', 4, 'What did God tell Moses to preserve for future generations?', 'An omer of manna was to be kept in a pot before the LORD as a testimony for generations to come', 'A piece of the Red Sea', 'A brick from Egypt', 'A staff from the burning bush', 'a', 'Exodus 16:32-33 — "And Moses said, This is the thing which the LORD commandeth, Fill an omer of it to be kept for your generations; that they may see the bread wherewith I have fed you in the wilderness."'),
('Exodus', 16, 'teens', 5, 'How long did the Israelites eat manna?', 'Forty years — until they came to the border of the land of Canaan', 'One year', 'Ten years', 'One hundred years', 'a', 'Exodus 16:35 — "And the children of Israel did eat manna forty years, until they came to a land inhabited; they did eat manna, until they came unto the borders of the land of Canaan."'),
-- Adults
('Exodus', 16, 'adults', 1, 'How does Jesus use the manna narrative in John 6?', 'Jesus declares Himself the "true bread from heaven" (John 6:32-35) — the manna sustained physical life temporarily, but Christ gives eternal life; the manna typologically points to Christ as God''s provision for humanity''s deepest need', 'Jesus never mentions manna', 'Jesus criticises the manna tradition', 'The connection is coincidental', 'a', 'John 6:31-35,48-51 — "Your fathers did eat manna in the wilderness, and are dead. I am the living bread which came down from heaven: if any man eat of this bread, he shall live for ever." Jesus interprets the manna typologically as pointing to Himself.'),
('Exodus', 16, 'adults', 2, 'What does the equal distribution principle (16:18) teach about God''s economy?', 'Paul quotes this passage in 2 Corinthians 8:15 to argue for economic equality among believers — God''s provision creates a community of sufficiency, not surplus and scarcity; this challenges both hoarding and laziness', 'It promotes individual accumulation', 'It has no New Testament relevance', 'It was a one-time event', 'a', '2 Corinthians 8:15 — "As it is written, He that had gathered much had nothing over; and he that had gathered little had no lack." Paul applies the manna principle to generosity within the church, arguing that God''s provision should flow to create equality.'),
('Exodus', 16, 'adults', 3, 'What does the Sabbath manna pattern establish theologically?', 'It roots the Sabbath in divine provision, not merely divine command — God models rest by providing double on the sixth day; the Sabbath is presented as trust that God provides enough so that work can cease', 'The Sabbath was already established here', 'The manna pattern contradicts the Sabbath', 'No Sabbath pattern exists here', 'a', 'Exodus 16:22-30 — The Sabbath manna instructions precede the formal Sabbath commandment at Sinai (20:8-11), establishing it through practice before codifying it in law. The double portion on day six teaches that rest is possible because God is faithful.'),
('Exodus', 16, 'adults', 4, 'How does God''s statement "I will prove them, whether they will walk in my law, or no" (16:4) connect manna to obedience?', 'Manna was not merely provision but a test of faith — would Israel trust God daily (not hoarding), rest on the Sabbath (double portion), and follow specific instructions? The daily bread became a daily examination of covenant faithfulness', 'The test was unfair', 'Israel passed easily', 'There was no test involved', 'a', 'Exodus 16:4 — "Behold, I will rain bread from heaven for you; and the people shall go out and gather a certain rate every day, that I may prove them." Deuteronomy 8:3 later explains: God humbled Israel with manna "to know what was in thine heart, whether thou wouldest keep his commandments, or no."'),
('Exodus', 16, 'adults', 5, 'What is the eschatological significance of the hidden manna in Revelation 2:17?', 'Christ promises "hidden manna" to overcomers — connecting wilderness provision to heavenly reward; the manna preserved in the ark (Exodus 16:33, Hebrews 9:4) becomes a symbol of God''s eternal provision for His faithful people', 'There is no connection', 'The manna in Revelation is literal', 'It refers to earthly food', 'a', 'Revelation 2:17 — "To him that overcometh will I give to eat of the hidden manna." The jar of manna kept in the ark (hidden in the Holy of Holies) becomes a symbol of the heavenly provision reserved for those who endure faithfully.'),
('Exodus', 16, 'adults', 6, 'How does Israel''s complaint "would to God we had died by the hand of the LORD in Egypt" reveal a distorted memory?', 'Israel idealises slavery — remembering "sitting by the flesh pots" and eating "bread to the full" while forgetting the bitter bondage; this selective memory pattern (nostalgia for bondage) recurs throughout the wilderness and mirrors how sin romanticises past captivity', 'Their memory was accurate', 'Egypt was truly better', 'They had a valid complaint', 'a', 'Exodus 16:3 — "Would to God we had died by the hand of the LORD in the land of Egypt, when we sat by the flesh pots, and when we did eat bread to the full." The Hebrew narrative uses irony: they romanticise the house of bondage while standing in the wilderness of freedom.'),
('Exodus', 16, 'adults', 7, 'What is the connection between "in the morning ye shall see the glory of the LORD" and the manna?', 'The manna itself is a manifestation of God''s glory — daily provision is not merely physical sustenance but a visible display of divine presence and care; seeing God''s glory in ordinary provision is a key spiritual discipline', 'Glory refers only to the cloud', 'Manna and glory are unrelated', 'Glory appeared only at Sinai', 'a', 'Exodus 16:7 — "In the morning, then ye shall see the glory of the LORD." The glory (kavod) is connected to the provision of bread — God''s glory is revealed not only in spectacular theophanies but in the daily faithfulness of feeding His people.'),
('Exodus', 16, 'adults', 8, 'How does the Lord''s Prayer petition "Give us this day our daily bread" echo the manna narrative?', 'Jesus deliberately echoes the daily manna pattern — just as Israel received "a certain rate every day" and could not hoard, believers are taught to depend on God for daily provision, cultivating trust rather than anxiety', 'The Lord''s Prayer has no OT background', 'Jesus was thinking of Roman bread', 'The echo is unintentional', 'a', 'Matthew 6:11 — "Give us this day our daily bread." The Greek epiousios ("daily/for today") directly parallels the manna instruction of daily gathering (Exodus 16:4). Both teach radical dependence on God''s daily faithfulness rather than anxious accumulation.');

-- ═══ Exodus Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 17, 'kids', 1, 'What did Moses do when the people were very thirsty at Rephidim?', 'God told him to strike the rock with his rod, and water came out of it', 'He dug a well', 'He prayed for rain', 'He found a river', 'a', 'Exodus 17:6 — "Behold, I will stand before thee there upon the rock in Horeb; and thou shalt smite the rock, and there shall come water out of it, that the people may drink."'),
('Exodus', 17, 'kids', 2, 'Who attacked the Israelites at Rephidim?', 'The Amalekites', 'The Egyptians', 'The Philistines', 'The Canaanites', 'a', 'Exodus 17:8 — "Then came Amalek, and fought with Israel in Rephidim."'),
('Exodus', 17, 'kids', 3, 'What happened when Moses held up his hands during the battle?', 'Israel won, but when his hands went down, Amalek won — so Aaron and Hur held up his hands until sunset', 'Nothing special happened', 'It started raining', 'The ground shook', 'a', 'Exodus 17:11-12 — "And it came to pass, when Moses held up his hand, that Israel prevailed: and when he let down his hand, Amalek prevailed. But Moses'' hands were heavy... and Aaron and Hur stayed up his hands."'),
-- Teens
('Exodus', 17, 'teens', 1, 'Why did Moses name the place Massah and Meribah?', 'Massah means "testing" and Meribah means "quarrelling" — because the people tested the LORD saying "Is the LORD among us, or not?"', 'They were named after local kings', 'They were beautiful places', 'Moses named them after his sons', 'a', 'Exodus 17:7 — "And he called the name of the place Massah, and Meribah, because of the chiding of the children of Israel, and because they tempted the LORD, saying, Is the LORD among us, or not?"'),
('Exodus', 17, 'teens', 2, 'Who did Moses choose to lead the army against Amalek?', 'Joshua — this is the first mention of Joshua in the Bible', 'Aaron', 'Caleb', 'Hur', 'a', 'Exodus 17:9 — "And Moses said unto Joshua, Choose us out men, and go out, fight with Amalek."'),
('Exodus', 17, 'teens', 3, 'What did Moses build after the victory over Amalek?', 'An altar called Jehovah-Nissi, meaning "The LORD is my Banner"', 'A large house', 'A fortress wall', 'A golden statue', 'a', 'Exodus 17:15 — "And Moses built an altar, and called the name of it Jehovahnissi."'),
('Exodus', 17, 'teens', 4, 'What did God say about the future of the Amalekites?', 'God would utterly blot out the remembrance of Amalek from under heaven and have war with Amalek from generation to generation', 'They would become Israel''s friends', 'They would rule the earth', 'They would be forgiven', 'a', 'Exodus 17:14,16 — "I will utterly put out the remembrance of Amalek from under heaven... the LORD will have war with Amalek from generation to generation."'),
('Exodus', 17, 'teens', 5, 'Who were the two men who held up Moses'' arms?', 'Aaron and Hur — they sat Moses on a stone and supported his hands, one on each side', 'Joshua and Caleb', 'Jethro and Zipporah', 'Nadab and Abihu', 'a', 'Exodus 17:12 — "And Aaron and Hur stayed up his hands, the one on the one side, and the other on the other side; and his hands were steady until the going down of the sun."'),
-- Adults
('Exodus', 17, 'adults', 1, 'How does Paul interpret the rock that gave water in 1 Corinthians 10:4?', 'Paul identifies the rock as Christ — "they drank of that spiritual Rock that followed them: and that Rock was Christ" — presenting Christ as the source of spiritual sustenance throughout Israel''s wilderness journey', 'Paul makes no reference to this event', 'Paul says the rock was literal only', 'Paul identifies the rock as Moses', 'a', '1 Corinthians 10:4 — "And did all drink the same spiritual drink: for they drank of that spiritual Rock that followed them: and that Rock was Christ." Paul''s typological reading identifies Christ as the source of life-giving sustenance, present with Israel in the wilderness.'),
('Exodus', 17, 'adults', 2, 'What does the question "Is the LORD among us, or not?" reveal as the fundamental crisis?', 'It exposes the core temptation in the wilderness: doubting God''s presence despite overwhelming evidence (plagues, Red Sea, manna); this is the sin of testing God — demanding proof of what He has already demonstrated', 'It was a reasonable question', 'They had no evidence of God''s presence', 'Moses encouraged the question', 'a', 'Exodus 17:7 — "Is the LORD among us, or not?" This question comes after ten plagues, the Red Sea, the pillar of cloud/fire, and daily manna. It reveals that spiritual amnesia is a persistent human tendency — past faithfulness does not immunise against present doubt.'),
('Exodus', 17, 'adults', 3, 'How does Moses'' raised hands function theologically in the Amalek battle?', 'The raised hands with the rod of God represent prayer and dependence on divine power — the battle''s outcome depends not on military skill but on sustained intercession; this pictures the priestly ministry of intercession that sustains God''s people', 'Moses was signalling troop movements', 'The raised hands were superstition', 'Only Joshua''s fighting mattered', 'a', 'Exodus 17:11-12 — The connection between raised hands and military success demonstrates the priority of prayer over prowess. Moses'' hands with the rod (matteh ha-Elohim) represent divine authority channelled through faithful intercession.'),
('Exodus', 17, 'adults', 4, 'What is the typological significance of Aaron and Hur supporting Moses'' hands?', 'It demonstrates that no spiritual leader can sustain the burden alone — the body of Christ requires mutual support in intercession; those who hold up the leader''s hands participate in the victory as much as those fighting on the battlefield', 'Aaron and Hur were unnecessary', 'Moses was simply tired', 'It was a one-time arrangement', 'a', 'Exodus 17:12 — Aaron and Hur''s support is a paradigm for ministry partnership. The victory required three roles: Moses interceding, Joshua fighting, Aaron and Hur supporting — all indispensable. This prefigures the body of Christ where every member is essential.'),
('Exodus', 17, 'adults', 5, 'Why does God command the eradication of Amalek, and how does this connect to later history?', 'Amalek attacked Israel''s weakest and most vulnerable from the rear (Deuteronomy 25:17-18) — this unprovoked cruelty against the defenceless makes Amalek a perpetual enemy; the conflict continues through Saul (1 Samuel 15) and Haman the Agagite (Esther)', 'The conflict was temporary', 'Amalek was innocent', 'God later forgave Amalek', 'a', 'Deuteronomy 25:17-18 — "He met thee by the way, and smote the hindmost of thee, even all that were feeble behind thee, when thou wast faint and weary." Amalek''s cowardice in attacking stragglers and the weak earned perpetual divine judgment.'),
('Exodus', 17, 'adults', 6, 'What does the name Jehovah-Nissi ("The LORD is my Banner") signify?', 'A banner (nes) in ancient warfare was the rallying point for troops — declaring God as the banner means He is the cause, the rallying point, and the source of victory, not human military power', 'It refers to a physical flag', 'Moses named it after himself', 'It means "God of war"', 'a', 'Exodus 17:15 — Jehovah-Nissi declares that the LORD Himself is the standard around which Israel rallies. Isaiah 11:10 prophecies that the Messiah will stand as "an ensign (nes) of the people" — the ultimate banner.'),
('Exodus', 17, 'adults', 7, 'How does the water-from-rock incident connect to the broader wilderness testing theme?', 'Each crisis (hunger/manna ch.16, thirst/rock ch.17, war/Amalek ch.17) tests whether Israel will trust God''s provision — the escalating challenges prepare them for covenant commitment at Sinai; trust must be established before law is given', 'The tests were random', 'Israel passed all tests easily', 'Tests and covenant are unrelated', 'a', 'The wilderness testing sequence is pedagogical: after salvation (ch.14), God tests provision-trust (ch.16-17) before giving the covenant (ch.19-20). Each test reveals Israel''s heart and God''s faithfulness, establishing the relationship foundation for the law.'),
('Exodus', 17, 'adults', 8, 'What is the significance of God saying "I will stand before thee there upon the rock"?', 'God places Himself on the rock that Moses strikes — God absorbs the blow intended for the guilty people; the rock struck for water becomes a picture of God Himself being struck so that life-giving water flows to the thirsty', 'God was merely indicating a location', 'The rock had no special significance', 'God stood beside the rock, not on it', 'a', 'Exodus 17:6 — "I will stand before thee there upon the rock in Horeb." God positions Himself upon the rock that is struck. In Numbers 20:8, God commands Moses to speak to the rock (not strike it) — striking it again (as Moses did) was a violation because Christ was to be struck only once (Hebrews 9:28).');

-- ═══ Exodus Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 18, 'kids', 1, 'Who came to visit Moses in the wilderness?', 'His father-in-law Jethro (also called Reuel), bringing Moses'' wife Zipporah and his two sons', 'Pharaoh', 'Abraham', 'The king of Midian', 'a', 'Exodus 18:5 — "And Jethro, Moses'' father in law, came with his sons and his wife unto Moses into the wilderness, where he encamped at the mount of God."'),
('Exodus', 18, 'kids', 2, 'What problem did Jethro notice about Moses?', 'Moses was sitting alone judging all the people from morning to evening — he was doing too much by himself', 'Moses was sleeping too much', 'Moses was eating too much', 'Moses was playing games', 'a', 'Exodus 18:13-14 — "And it came to pass on the morrow, that Moses sat to judge the people: and the people stood by Moses from the morning unto the evening."'),
('Exodus', 18, 'kids', 3, 'What good advice did Jethro give Moses?', 'Choose able, God-fearing men to help judge the smaller matters so Moses only handles the hard cases', 'Build a bigger tent', 'Hire more soldiers', 'Move to a new camp', 'a', 'Exodus 18:21-22 — "Moreover thou shalt provide out of all the people able men, such as fear God, men of truth, hating covetousness; and place such over them, to be rulers of thousands, and rulers of hundreds, rulers of fifties, and rulers of tens."'),
-- Teens
('Exodus', 18, 'teens', 1, 'What was Jethro''s reaction when Moses told him everything God had done?', 'He rejoiced, said "Blessed be the LORD," confessed "Now I know that the LORD is greater than all gods," and offered burnt offerings and sacrifices', 'He was sceptical', 'He was jealous', 'He ignored Moses', 'a', 'Exodus 18:9-11 — "And Jethro rejoiced for all the goodness which the LORD had done to Israel... And Jethro said, Blessed be the LORD... Now I know that the LORD is greater than all gods."'),
('Exodus', 18, 'teens', 2, 'What four qualities did Jethro say the appointed judges must have?', 'Able men, who fear God, men of truth, and hating covetousness', 'Rich, powerful, popular, and educated', 'Old, experienced, strong, and tall', 'Young, healthy, married, and landowners', 'a', 'Exodus 18:21 — "Thou shalt provide out of all the people able men, such as fear God, men of truth, hating covetousness."'),
('Exodus', 18, 'teens', 3, 'What hierarchy of leadership did Jethro suggest?', 'Rulers of thousands, hundreds, fifties, and tens — a tiered judicial system', 'One leader for everyone', 'Two leaders total', 'Twelve leaders for twelve tribes', 'a', 'Exodus 18:21 — "Place such over them, to be rulers of thousands, and rulers of hundreds, rulers of fifties, and rulers of tens."'),
('Exodus', 18, 'teens', 4, 'What warning did Jethro give Moses about his current approach?', '"Thou wilt surely wear away, both thou, and this people that is with thee: for this thing is too heavy for thee; thou art not able to perform it thyself alone"', '"You are doing a great job"', '"The people do not need judges"', '"Only you can do this work"', 'a', 'Exodus 18:18 — "Thou wilt surely wear away, both thou, and this people that is with thee: for this thing is too heavy for thee; thou art not able to perform it thyself alone."'),
('Exodus', 18, 'teens', 5, 'Did Moses follow Jethro''s advice?', 'Yes — Moses hearkened to his father-in-law and did all that he had said', 'No, he rejected it', 'He followed only part of it', 'He asked God first and God said no', 'a', 'Exodus 18:24 — "So Moses hearkened to the voice of his father in law, and did all that he had said."'),
-- Adults
('Exodus', 18, 'adults', 1, 'What does Jethro''s declaration "Now I know that the LORD is greater than all gods" suggest about his faith?', 'It appears to be a genuine confession of faith in Yahweh''s supremacy — some see it as conversion, others as a Midianite priest acknowledging Yahweh''s uniqueness within a henotheistic framework that gradually moves toward monotheism', 'Jethro was already a Yahweh worshipper', 'Jethro was being polite', 'Jethro rejected Yahweh', 'a', 'Exodus 18:11 — "Now I know that the LORD is greater than all gods: for in the thing wherein they dealt proudly he was above them." The phrase "in the thing wherein they dealt proudly" echoes measure-for-measure judgment — God overcame the Egyptians precisely where they boasted.'),
('Exodus', 18, 'adults', 2, 'What leadership principle does Jethro''s advice establish?', 'Delegation is not weakness but wisdom — effective leadership requires distributing authority among qualified people, reserving only the most significant matters for the top leader; this principle underlies both biblical and modern governance structures', 'Leaders must do everything themselves', 'Delegation shows lack of faith', 'Only prophets can judge', 'a', 'Exodus 18:17-23 — Jethro''s counsel introduces the principle of subsidiary — handling matters at the lowest competent level. This structure later becomes the basis for Israel''s judicial system (Deuteronomy 1:9-18) and informs the New Testament model of shared eldership.'),
('Exodus', 18, 'adults', 3, 'What is significant about God''s guidance coming through a non-Israelite?', 'Jethro is a Midianite priest, yet his wisdom shapes Israel''s governance — demonstrating that God can use outsiders to bless His people, and that common-grace wisdom is not limited to the covenant community', 'Only Israelites could give good advice', 'Jethro''s advice was flawed', 'Non-Israelites were enemies', 'a', 'Exodus 18:19-24 — God''s providential guidance through Jethro — a non-Israelite — foreshadows the inclusion of Gentile wisdom (Proverbs'' use of Egyptian wisdom texts) and the eventual Gentile inclusion in God''s purposes.'),
('Exodus', 18, 'adults', 4, 'How does the four-fold qualification for judges reflect biblical leadership standards?', 'Ability (competence), fear of God (vertical accountability), truthfulness (integrity), and hatred of covetousness (incorruptibility) — these four standards recur throughout Scripture for all leadership positions', 'Only ability matters', 'Wealth was the primary qualification', 'Family connections were essential', 'a', 'Exodus 18:21 — The qualifications cover: skill (chayil — able/capable), piety (fear of God), character (men of truth/emet), and financial integrity (hating covetousness/betza). These four criteria form a holistic leadership profile that applies across vocations.'),
('Exodus', 18, 'adults', 5, 'How does chapter 18 function as a literary bridge between the wilderness journey and the Sinai covenant?', 'It transitions from narrative (exodus/wilderness) to law (Sinai) by establishing the judicial infrastructure needed to administer the laws about to be given — you need judges before you can have justice; governance precedes legislation', 'It is a random insertion', 'It belongs after chapter 20', 'It has no structural function', 'a', 'Chapter 18 is strategically placed: before the law is given (chs.19-24), the judicial system to administer it is established. This sequence — governance infrastructure first, then legislation — reflects sound institutional design.'),
('Exodus', 18, 'adults', 6, 'What does Moses'' willingness to accept his father-in-law''s counsel reveal?', 'True humility in leadership — Moses, who spoke face-to-face with God, accepts practical wisdom from a human advisor; greatness is not diminished by receiving help but by refusing it', 'Moses was weak and indecisive', 'Moses had no choice', 'Moses regretted it later', 'a', 'Exodus 18:24 — "Moses hearkened to the voice of his father in law." The man to whom God spoke from the burning bush humbly accepts organisational advice from his father-in-law. This models Proverbs 12:15: "The way of a fool is right in his own eyes: but he that hearkeneth unto counsel is wise."'),
('Exodus', 18, 'adults', 7, 'What does Jethro''s meal with Aaron and the elders "before God" (18:12) suggest?', 'It was a covenant meal — eating together before God signified fellowship, unity, and possibly Jethro''s incorporation into the worshipping community; it parallels the covenant meal of Exodus 24:11', 'It was an ordinary dinner', 'Jethro ate alone', 'The meal had no religious significance', 'a', 'Exodus 18:12 — "And Jethro, Moses'' father in law, took a burnt offering and sacrifices for God: and Aaron came, and all the elders of Israel, to eat bread with Moses'' father in law before God." The phrase "before God" (liphnei ha-Elohim) marks this as a sacred, covenant-related meal.'),
('Exodus', 18, 'adults', 8, 'How does Jethro''s role as "priest of Midian" connect to the pre-Sinaitic worship tradition?', 'Jethro represents a legitimate non-Israelite priesthood — possibly descended from Abraham through Keturah (Genesis 25:1-2), preserving Abrahamic worship outside the covenant line; his offering and confession suggest continuity with patriarchal faith', 'Midianite worship was entirely pagan', 'Jethro had no religious role', 'Midian and Israel were unrelated', 'a', 'Exodus 18:1,12 — Jethro (priest of Midian) offers burnt offerings to Elohim. If Midianites descended from Abraham via Keturah, some knowledge of the true God may have been preserved. Jethro may represent a "Melchizedek-like" figure — a legitimate priest outside the Mosaic system.');

-- ═══ Exodus Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 19, 'kids', 1, 'Where did the Israelites camp when they reached the mountain?', 'At Mount Sinai — in the wilderness of Sinai, in the third month after leaving Egypt', 'At the top of Mount Sinai', 'By the Red Sea', 'In a large city', 'a', 'Exodus 19:1-2 — "In the third month, when the children of Israel were gone forth out of the land of Egypt, the same day came they into the wilderness of Sinai... and there Israel camped before the mount."'),
('Exodus', 19, 'kids', 2, 'What special thing did God say the Israelites would be if they obeyed Him?', 'A peculiar treasure, a kingdom of priests, and a holy nation', 'The richest people in the world', 'The biggest army on earth', 'The tallest people alive', 'a', 'Exodus 19:5-6 — "Now therefore, if ye will obey my voice indeed, and keep my covenant, then ye shall be a peculiar treasure unto me above all people... And ye shall be unto me a kingdom of priests, and an holy nation."'),
('Exodus', 19, 'kids', 3, 'What amazing things happened when God came down on Mount Sinai?', 'Thunder, lightning, thick cloud, loud trumpet sound, smoke, fire, and the whole mountain quaked greatly', 'A rainbow appeared', 'Flowers bloomed everywhere', 'The sun got very bright', 'a', 'Exodus 19:16,18 — "And it came to pass on the third day in the morning, that there were thunders and lightnings, and a thick cloud upon the mount, and the voice of the trumpet exceeding loud... And mount Sinai was altogether on a smoke... and the whole mount quaked greatly."'),
-- Teens
('Exodus', 19, 'teens', 1, 'What beautiful metaphor did God use for how He delivered Israel?', '"I bare you on eagles'' wings, and brought you unto myself"', '"I carried you on a golden chariot"', '"I led you through a tunnel"', '"I flew you on a magic carpet"', 'a', 'Exodus 19:4 — "Ye have seen what I did unto the Egyptians, and how I bare you on eagles'' wings, and brought you unto myself."'),
('Exodus', 19, 'teens', 2, 'What did the people have to do to prepare for God''s appearance?', 'Consecrate (sanctify) themselves, wash their clothes, and not touch the mountain — anyone who touched it would die', 'Build a temple', 'Fast for forty days', 'Climb to the mountain top', 'a', 'Exodus 19:10-12 — "And the LORD said unto Moses, Go unto the people, and sanctify them to day and to morrow, and let them wash their clothes... whosoever toucheth the mount shall be surely put to death."'),
('Exodus', 19, 'teens', 3, 'What did the people say when Moses told them God''s words?', '"All that the LORD hath spoken we will do" — they agreed unanimously', '"We need more time to think"', '"We will obey most of it"', '"We are not sure"', 'a', 'Exodus 19:8 — "And all the people answered together, and said, All that the LORD hath spoken we will do."'),
('Exodus', 19, 'teens', 4, 'What happened when the trumpet sound grew louder and louder?', 'Moses spoke and God answered him by a voice — a direct divine-human conversation on the mountain', 'Everyone fell asleep', 'The mountain split in half', 'The sky turned green', 'a', 'Exodus 19:19 — "And when the voice of the trumpet sounded long, and waxed louder and louder, Moses spake, and God answered him by a voice."'),
('Exodus', 19, 'teens', 5, 'What strict boundary was set around the mountain?', 'No person or animal could touch the base of the mountain on penalty of death — shot through with arrows or stoned', 'Only Moses could see the mountain', 'The mountain was invisible', 'There were no restrictions', 'a', 'Exodus 19:12-13 — "And thou shalt set bounds unto the people round about, saying, Take heed to yourselves, that ye go not up into the mount, or touch the border of it: whosoever toucheth the mount shall be surely put to death."'),
-- Adults
('Exodus', 19, 'adults', 1, 'What is the significance of the phrase "kingdom of priests and holy nation" for Israel''s identity?', 'It defines Israel''s vocation: every Israelite has a priestly role — mediating God''s presence to the world; they are not merely chosen for privilege but for service, prefiguring 1 Peter 2:9 where the church is called a "royal priesthood"', 'It means Israel would all become professional priests', 'It was a temporary designation', 'It had no practical implications', 'a', 'Exodus 19:6 — "A kingdom of priests, and an holy nation." Israel''s priestly vocation is corporate — the entire nation functions as priests to the world. 1 Peter 2:9 explicitly applies this to the church: "a chosen generation, a royal priesthood, an holy nation."'),
('Exodus', 19, 'adults', 2, 'How does the Sinai theophany function as a model for biblical encounters with God?', 'It establishes the pattern: preparation (sanctification, v.10), divine descent (v.18), mediator (Moses, v.20), boundaries (v.12), and awe/fear (v.16) — every subsequent encounter with God in Scripture echoes these elements', 'Sinai was unique and unrepeatable', 'Later encounters are identical', 'There is no pattern', 'a', 'The Sinai theophany provides the template for experiencing God''s presence: holiness demands preparation, God''s approach inspires fear, mediation is necessary, and boundaries protect the profane from the holy. These elements recur from tabernacle worship to the Mount of Transfiguration.'),
('Exodus', 19, 'adults', 3, 'What is the covenant structure of Exodus 19 and how does it parallel ancient Near Eastern treaties?', 'It follows the suzerainty treaty pattern: historical prologue ("what I did to Egypt," v.4), stipulations ("if ye will obey," v.5), and blessings ("peculiar treasure," v.5-6) — God uses a familiar political form to establish His covenant', 'It follows no recognizable pattern', 'It is purely religious', 'It contradicts treaty forms', 'a', 'Exodus 19:3-6 mirrors Hittite suzerainty treaties: preamble (God speaking), historical prologue (deliverance from Egypt), covenant demands (obey my voice), and covenant privileges (treasured possession, priestly kingdom). God accommodates His covenant to understood political forms.'),
('Exodus', 19, 'adults', 4, 'What does the "eagles'' wings" metaphor (19:4) convey about God''s deliverance?', 'It combines power (eagle''s strength), tenderness (bearing young), safety (above danger), and personal care (unto myself) — Deuteronomy 32:11 expands this, describing how an eagle stirs its nest, flutters over its young, and bears them on its wings', 'Eagles were Egyptian symbols', 'It is a generic metaphor', 'It refers to speed only', 'a', 'Exodus 19:4 — "I bare you on eagles'' wings, and brought you unto myself." The eagle metaphor (cf. Deuteronomy 32:11, Isaiah 40:31) conveys protective power, parental nurture, and the goal: "unto myself" — redemption''s purpose is intimate relationship with God.'),
('Exodus', 19, 'adults', 5, 'How does Hebrews 12:18-24 contrast the Sinai experience with the new covenant?', 'Hebrews contrasts the terrifying Sinai theophany (fire, darkness, tempest, trumpet, voice) with Mount Zion''s grace — believers come not to a mountain that cannot be touched but to the heavenly Jerusalem, to Jesus the mediator of a better covenant', 'Hebrews affirms Sinai''s superiority', 'There is no contrast', 'Hebrews ignores the Sinai event', 'a', 'Hebrews 12:18-24 — "For ye are not come unto the mount that might be touched, and that burned with fire... But ye are come unto mount Sion... to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel."'),
('Exodus', 19, 'adults', 6, 'What does "the LORD descended upon it in fire" reveal about the nature of theophany?', 'Fire represents God''s holiness, glory, and consuming nature — it both reveals and conceals; God is present (in the fire) yet hidden (in the smoke and cloud), establishing that God can be known but never fully comprehended', 'Fire was merely dramatic', 'The mountain actually erupted', 'Fire was coincidental', 'a', 'Exodus 19:18 — "Mount Sinai was altogether on a smoke, because the LORD descended upon it in fire." Fire as theophanic medium appears at the burning bush (3:2), the pillar (13:21), Sinai (19:18), and Pentecost (Acts 2:3). It signifies divine presence that purifies and illuminates.'),
('Exodus', 19, 'adults', 7, 'Why does grace precede law in the Exodus narrative sequence?', 'God delivers Israel (grace, chs.1-18) before giving the law (chs.19-24) — obedience is a response to grace, not a condition for it; Israel is not saved by keeping the law but saved to keep the law, establishing the biblical order: indicative before imperative', 'Law came first historically', 'Grace and law are unrelated', 'The order is coincidental', 'a', 'The narrative structure is theologically significant: redemption (Exodus 1-18) precedes legislation (Exodus 19-24). God did not say "keep these laws and I will deliver you" but "I have delivered you, now keep my covenant." This grace-then-response pattern is the foundation of biblical ethics.'),
('Exodus', 19, 'adults', 8, 'What is the significance of "the whole mount quaked greatly" during the theophany?', 'The earthquake signifies that creation itself responds to its Creator''s presence — the physical world trembles before its Maker, echoing the cosmic-shaking that accompanies divine judgment (Haggai 2:6, Hebrews 12:26) and anticipating eschatological renewal', 'It was a natural earthquake', 'It was an illusion', 'Mountains do not quake', 'a', 'Exodus 19:18 — "The whole mount quaked greatly." The seismic response of creation to God''s presence is a consistent biblical motif: Psalm 68:8, 114:4-7, Nahum 1:5, Habakkuk 3:6. Hebrews 12:26 promises a final shaking "not the earth only, but also heaven."');

-- ═══ Exodus Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Exodus', 20, 'kids', 1, 'How many commandments did God give the Israelites?', 'Ten Commandments', 'Five Commandments', 'Twenty Commandments', 'One Hundred Commandments', 'a', 'Exodus 20:1-17 — God spoke ten foundational commandments, covering our relationship with God (commandments 1-4) and with other people (commandments 5-10).'),
('Exodus', 20, 'kids', 2, 'What is the very first commandment?', '"Thou shalt have no other gods before me" — God must be first in our lives', '"Be nice to your neighbours"', '"Do not eat too much"', '"Go to church every day"', 'a', 'Exodus 20:3 — "Thou shalt have no other gods before me."'),
('Exodus', 20, 'kids', 3, 'Which commandment tells children to respect their parents?', '"Honour thy father and thy mother" — the fifth commandment', '"Do not steal"', '"Do not lie"', '"Do not covet"', 'a', 'Exodus 20:12 — "Honour thy father and thy mother: that thy days may be long upon the land which the LORD thy God giveth thee."'),
-- Teens
('Exodus', 20, 'teens', 1, 'What does the second commandment prohibit?', 'Making any graven image or likeness of anything in heaven, earth, or water to worship — God is spirit and must not be reduced to an image', 'Having more than one Bible', 'Drawing pictures of any kind', 'Building houses of worship', 'a', 'Exodus 20:4-5 — "Thou shalt not make unto thee any graven image, or any likeness of any thing that is in heaven above, or that is in the earth beneath, or that is in the water under the earth: Thou shalt not bow down thyself to them, nor serve them."'),
('Exodus', 20, 'teens', 2, 'What does it mean to "take the name of the LORD thy God in vain"?', 'Using God''s name carelessly, falsely, or disrespectfully — treating His holy name as meaningless or common', 'Never saying God''s name at all', 'Only saying God''s name in Hebrew', 'Singing hymns too loudly', 'a', 'Exodus 20:7 — "Thou shalt not take the name of the LORD thy God in vain; for the LORD will not hold him guiltless that taketh his name in vain."'),
('Exodus', 20, 'teens', 3, 'What reason does the fourth commandment give for keeping the Sabbath?', 'Because God created the heaven and earth in six days and rested the seventh day — the Sabbath follows God''s creation pattern', 'Because people need exercise', 'Because it saves money', 'Because animals need rest', 'a', 'Exodus 20:11 — "For in six days the LORD made heaven and earth, the sea, and all that in them is, and rested the seventh day: wherefore the LORD blessed the sabbath day, and hallowed it."'),
('Exodus', 20, 'teens', 4, 'What is the tenth commandment about?', '"Thou shalt not covet" — do not desire your neighbour''s house, wife, servant, ox, donkey, or anything that belongs to your neighbour', 'Do not travel on Saturdays', 'Do not eat certain foods', 'Do not work at night', 'a', 'Exodus 20:17 — "Thou shalt not covet thy neighbour''s house, thou shalt not covet thy neighbour''s wife, nor his manservant, nor his maidservant, nor his ox, nor his ass, nor any thing that is thy neighbour''s."'),
('Exodus', 20, 'teens', 5, 'What happened when the people experienced the thunder, lightning, and trumpet at Sinai?', 'They trembled and stood far off, asking Moses to speak to them instead of God — "Let not God speak with us, lest we die"', 'They ran up the mountain', 'They danced and celebrated', 'They fell asleep', 'a', 'Exodus 20:18-19 — "And all the people saw the thunderings, and the lightnings, and the noise of the trumpet, and the mountain smoking: and when the people saw it, they removed, and stood afar off. And they said unto Moses, Speak thou with us, and we will hear: but let not God speak with us, lest we die."'),
-- Adults
('Exodus', 20, 'adults', 1, 'How does the preamble "I am the LORD thy God, which have brought thee out of the land of Egypt" frame the entire Decalogue?', 'It establishes that the commandments flow from a relationship of grace — God identifies Himself as Redeemer before Lawgiver; obedience is a response to deliverance, not a condition for it; the indicative (what God has done) grounds the imperative (what Israel must do)', 'The preamble is irrelevant to the commands', 'It establishes law before grace', 'It was added later', 'a', 'Exodus 20:2 — The preamble is crucial: God does not begin with "Obey these rules." He begins with "I am the LORD thy God, which have brought thee out." This theological sequence — grace before law, redemption before requirement — is the foundation of biblical ethics.'),
('Exodus', 20, 'adults', 2, 'What does "visiting the iniquity of the fathers upon the children unto the third and fourth generation" mean?', 'It describes the natural consequences of sin — idolatry creates patterns that affect descendants; but God''s mercy extends to "thousands" (a thousand generations) of those who love Him, making mercy vastly disproportionate to judgment', 'God punishes innocent children for their parents'' sins', 'Each generation is completely independent', 'The third and fourth generation must pay a fine', 'a', 'Exodus 20:5-6 — The contrast is stark: judgment reaches 3-4 generations, but mercy extends to thousands. Ezekiel 18:20 clarifies individual accountability. The "visitation" describes inherited consequences (patterns, tendencies, environments) rather than transferred guilt.'),
('Exodus', 20, 'adults', 3, 'How does Jesus summarise the Ten Commandments in the Great Commandment?', 'He reduces them to two principles: love God (covering commandments 1-4) and love your neighbour (covering commandments 5-10), stating that all the law and prophets hang on these two', 'He replaces the commandments', 'He ignores the commandments', 'He adds new commandments', 'a', 'Matthew 22:37-40 — "Thou shalt love the Lord thy God with all thy heart... This is the first and great commandment. And the second is like unto it, Thou shalt love thy neighbour as thyself. On these two commandments hang all the law and the prophets."'),
('Exodus', 20, 'adults', 4, 'What is unique about the tenth commandment compared to the other nine?', 'It is the only commandment that addresses internal desire rather than external action — "thou shalt not covet" legislates the heart, acknowledging that sinful actions begin with sinful desires, making this commandment the bridge between law and gospel', 'It is the least important', 'It is identical to the ninth', 'It was added later', 'a', 'Exodus 20:17 — The tenth commandment moves from external behaviour to internal motivation. Paul says this commandment revealed his own sinfulness (Romans 7:7-8): "I had not known lust, except the law had said, Thou shalt not covet." It exposes the heart''s condition.'),
('Exodus', 20, 'adults', 5, 'How does the fifth commandment function as a bridge between the two tables of the law?', 'It transitions from God-directed commands (1-4) to human-directed commands (6-10) — honouring parents is both a reflection of honouring God (parents are God''s representatives) and the foundation for all social order; Paul calls it "the first commandment with promise"', 'It belongs with the first four', 'It is purely social', 'It has no special position', 'a', 'Exodus 20:12, Ephesians 6:2 — The fifth commandment bridges the two tables: honouring parents reflects honouring God (vertical) while establishing the foundational human relationship (horizontal). Paul identifies it as "the first commandment with promise" — long life in the land.'),
('Exodus', 20, 'adults', 6, 'What does "thou shalt not kill" (ratsach) mean in its original Hebrew context?', 'The Hebrew ratsach specifically means unlawful killing (murder) — not all forms of killing; the same law that prohibits ratsach elsewhere commands capital punishment and permits defensive warfare, making a distinction between murder and lawful taking of life', 'It prohibits all killing of any kind', 'It only applies to Israelites killing Israelites', 'It was a suggestion, not a command', 'a', 'Exodus 20:13 — The verb ratsach refers specifically to murder — unlawful, intentional killing. Numbers 35:16-21 elaborates on ratsach versus justified killing. The commandment does not address capital punishment (prescribed elsewhere) or warfare, but personal homicide.'),
('Exodus', 20, 'adults', 7, 'How does the people''s request for a mediator (20:19) anticipate the prophetic and priestly offices?', 'Their fear of God''s direct voice establishes the necessity of mediation — Moses becomes the prototype mediator, a role continued through the priesthood and prophets, and ultimately fulfilled in Christ who mediates a better covenant (Hebrews 8:6)', 'The request was rejected by God', 'No mediator was needed', 'Moses refused the role', 'a', 'Exodus 20:19 — "Speak thou with us, and we will hear: but let not God speak with us, lest we die." This request formalises the mediatorial principle: sinful humanity needs a go-between. Deuteronomy 18:15-18 connects this directly to the prophet like Moses — ultimately Christ.'),
('Exodus', 20, 'adults', 8, 'What does the prohibition against hewn stone altars (20:25) reveal about worship?', 'Human craftsmanship on the altar represents human effort added to divine provision — God''s altar must remain unadorned by human works, teaching that worship depends on God''s grace, not human embellishment; this principle underlies the Reformation''s emphasis on grace alone', 'Hewn stones were too expensive', 'Uncut stones were stronger', 'It was an architectural preference', 'a', 'Exodus 20:25 — "And if thou wilt make me an altar of stone, thou shalt not build it of hewn stone: for if thou lift up thy tool upon it, thou hast polluted it." Human modification "pollutes" the altar. The same principle appears in Joshua 8:31 and anticipates the temple''s stones being prepared offsite (1 Kings 6:7).');
